class Solution {
public:
    int longestSubsequence(string s, int k) {
        int n = s.size();
        int res = 0;
        for (int i = 0; i <= n; i++) {
            string t = s.substr(0, i);
            int num = stoi(t, 0, 2);
            if (num <= k) {
                res = max(res, (int)t.size());
            }
        }
        return res;
    }
};
